            magic_index = self.buffer.find(MAGIC)
            if magic_index < 0:
                if self.buffer and self.buffer[-1] == MAGIC[0]:
                    self.buffer[:] = self.buffer[-1:]
                else:
                    self.buffer[:] = b""
